541	fn addChooseTreeEntry(state: *ChooseTreeState, label: []const u8, depth: u8, has_children: bool, session: *Session, window: ?*Window, pane: ?*Pane) CmdError!void {
542	    const owned_label = state.allocator.dupe(u8, label) catch return CmdError.OutOfMemory;
543	    errdefer state.allocator.free(owned_label);
544	    state.labels.append(state.allocator, owned_label) catch return CmdError.OutOfMemory;
545	    state.tree.addItem(.{
546	        .label = owned_label,
547	        .depth = depth,
548	        .expanded = true,
549	        .has_children = has_children,
550	        .tag = @intCast(state.items.items.len),
551	    }) catch return CmdError.OutOfMemory;
552	    state.items.append(state.allocator, .{
553	        .session = @ptrCast(session),
554	        .window = if (window) |w| @ptrCast(w) else null,
555	        .pane = if (pane) |p| @ptrCast(p) else null,
556	    }) catch return CmdError.OutOfMemory;
