559	fn currentChooseTreeState(ctx: *Context, pane: ?*Pane) ?*ChooseTreeState {
560	    if (ctx.server.choose_tree_state) |*state| return state;
561	    if (ctx.client_index) |client_index| {
562	        if (client_index < ctx.server.clients.items.len) {
563	            if (ctx.server.clients.items[client_index].choose_tree_state) |*state| return state;
564	        }
565	    }
566	    if (pane) |p| {
567	        if (p.choose_tree_state) |*state| return state;
568	    }
569	    return null;
570	}
