576	    }
577	    if (ctx.client_index) |client_index| {
578	        if (client_index < ctx.server.clients.items.len) {
579	            if (ctx.server.clients.items[client_index].choose_tree_state) |*state| {
580	                state.deinit();
581	            }
582	            ctx.server.clients.items[client_index].choose_tree_state = null;
583	        }
584	    }
585	    if (pane) |p| {
