593	fn renderChooseTree(ctx: *Context, pane: ?*Pane) CmdError!void {
594	    const state = currentChooseTreeState(ctx, pane) orelse return CmdError.CommandFailed;
595	    const rendered = state.tree.render(ctx.allocator) catch return CmdError.OutOfMemory;
596	    defer ctx.allocator.free(rendered);
