600	fn handleChooseTreeSelect(ctx: *Context, pane: ?*Pane, item_index: usize) CmdError!void {
601	    const state = currentChooseTreeState(ctx, pane) orelse return CmdError.CommandFailed;
602	    if (item_index >= state.items.items.len) return CmdError.InvalidArgs;
603	    const item = state.items.items[item_index];
604	    const session: *Session = @ptrCast(@alignCast(item.session orelse return CmdError.SessionNotFound));
605	    ctx.session = session;
606	    ctx.server.default_session = session;
607	    if (item.window) |window_ptr| {
608	        const window: *Window = @ptrCast(@alignCast(window_ptr));
609	        session.selectWindow(window);
610	        ctx.window = window;
611	        if (item.pane) |pane_ptr| {
612	            const selected_pane: *Pane = @ptrCast(@alignCast(pane_ptr));
613	            window.selectPane(selected_pane);
614	            ctx.pane = selected_pane;
615	        } else {
616	            ctx.pane = window.active_pane;
617	        }
618	    } else {
619	        ctx.window = session.active_window;
620	        ctx.pane = if (ctx.window) |window| window.active_pane else null;
621	    }
622	    clearChooseTreeState(ctx, pane);
623	}
