625	fn handleChooseTreeKey(ctx: *Context, pane: ?*Pane, key_arg: []const u8) CmdError!bool {
626	    if (currentChooseTreeState(ctx, pane) == null) return false;
627	
628	    const key: u21 = if (key_string.stringToKey(key_arg)) |result|
629	        result.key
630	    else if (key_arg.len == 1)
631	        key_arg[0]
632	    else
633	        return false;
634	
635	    var state = currentChooseTreeState(ctx, pane) orelse return false;
636	    switch (state.tree.handleKey(key)) {
637	        .none => {
638	            try renderChooseTree(ctx, pane);
639	            return true;
640	        },
641	        .cancel => {
642	            clearChooseTreeState(ctx, pane);
643	            return true;
644	        },
645	        .select, .toggle_expand => {
646	            const selected = state.tree.selected;
647	            try handleChooseTreeSelect(ctx, pane, selected);
648	            return true;
649	        },
650	    }
651	}
