653	fn formatBindingKey(buf: []u8, key: u21, mods: binding_mod.Modifiers) []const u8 {
654	    var pos: usize = 0;
655	    if (mods.ctrl) {
656	        @memcpy(buf[pos .. pos + 2], "C-");
657	        pos += 2;
658	    }
659	    if (mods.meta) {
660	        @memcpy(buf[pos .. pos + 2], "M-");
661	        pos += 2;
662	    }
663	    if (mods.shift) {
664	        @memcpy(buf[pos .. pos + 2], "S-");
665	        pos += 2;
666	    }
667	
668	    const special: ?[]const u8 = switch (key) {
669	        '\r' => "Enter",
670	        0x1b => "Escape",
671	        ' ' => "Space",
672	        '\t' => "Tab",
673	        0x7f => "BSpace",
674	        0x100 => "Up",
675	        0x101 => "Down",
676	        0x102 => "Left",
677	        0x103 => "Right",
678	        else => null,
679	    };
680	
681	    if (special) |name| {
682	        @memcpy(buf[pos .. pos + name.len], name);
683	        pos += name.len;
684	        return buf[0..pos];
685	    }
686	
687	    if (key < 0x80) {
688	        buf[pos] = @truncate(key);
689	        pos += 1;
690	        return buf[0..pos];
691	    }
692	
693	    const rendered = std.fmt.bufPrint(buf[pos..], "U+{X}", .{key}) catch "?";
694	    return buf[0 .. pos + rendered.len];
695	}
