697	fn spawnShellChild(command: []const u8) CmdError!std.c.pid_t {
698	    var cmd_buf: [4096]u8 = .{0} ** 4096;
699	    if (command.len >= cmd_buf.len) return CmdError.CommandFailed;
700	    @memcpy(cmd_buf[0..command.len], command);
701	
702	    const pid = std.c.fork();
703	    if (pid < 0) return CmdError.CommandFailed;
704	
705	    if (pid == 0) {
706	        const sh: [*:0]const u8 = "/bin/sh";
707	        const c_flag: [*:0]const u8 = "-c";
708	        const cmd_z: [*:0]const u8 = @ptrCast(cmd_buf[0..command.len :0]);
709	        const argv = [_:null]?[*:0]const u8{ sh, c_flag, cmd_z };
710	        _ = execvp(sh, &argv);
711	        std.c.exit(127);
712	    }
713	
714	    return pid;
715	}
