872	fn cmdBindKey(ctx: *Context, args: []const []const u8) CmdError!void {
873	    const manager = ctx.binding_manager orelse {
874	        try writeReplyMessage(ctx, .error_msg, "bind-key: no binding manager available\n");
875	        return CmdError.CommandFailed;
876	    };
877	
878	    var table_name: []const u8 = "prefix";
879	    var i: usize = 0;
880	
881	    // Parse flags: -T table_name, -n (root table)
882	    while (i < args.len) {
883	        if (std.mem.eql(u8, args[i], "-T")) {
884	            i += 1;
885	            if (i >= args.len) return CmdError.InvalidArgs;
886	            table_name = args[i];
887	        } else if (std.mem.eql(u8, args[i], "-n")) {
888	            table_name = "root";
889	        } else {
890	            break;
891	        }
892	        i += 1;
893	    }
894	
895	    // Next arg is the key string
896	    if (i >= args.len) return CmdError.InvalidArgs;
897	    const kr = key_string.stringToKey(args[i]) orelse {
898	        try writeReplyMessage(ctx, .error_msg, "bind-key: unknown key\n");
899	        return CmdError.CommandFailed;
900	    };
901	    i += 1;
902	
903	    // Remaining args form the command
904	    if (i >= args.len) return CmdError.InvalidArgs;
905	    const cmd_parts = args[i..];
906	
907	    // Join command parts with spaces
908	    var total_len: usize = 0;
909	    for (cmd_parts, 0..) |part, idx| {
910	        total_len += part.len;
911	        if (idx < cmd_parts.len - 1) total_len += 1;
912	    }
913	    const cmd_str = ctx.allocator.alloc(u8, total_len) catch return CmdError.OutOfMemory;
914	    defer ctx.allocator.free(cmd_str);
915	    var pos: usize = 0;
916	    for (cmd_parts, 0..) |part, idx| {
917	        @memcpy(cmd_str[pos..][0..part.len], part);
918	        pos += part.len;
919	        if (idx < cmd_parts.len - 1) {
920	            cmd_str[pos] = ' ';
921	            pos += 1;
922	        }
923	    }
924	
925	    const table = manager.getOrCreateTable(table_name) catch return CmdError.OutOfMemory;
926	    table.bind(kr.key, kr.mods, cmd_str) catch return CmdError.OutOfMemory;
927	}
