1	const std = @import("std");
2	
3	/// Context for format string expansion.
4	pub const FormatContext = struct {
5	    session_name: []const u8 = "",
6	    session_id: u32 = 0,
7	    window_name: []const u8 = "",
8	    window_index: u32 = 0,
9	    window_active: bool = false,
10	    pane_index: u32 = 0,
11	    pane_title: []const u8 = "",
12	    pane_current_path: []const u8 = "",
13	    pane_pid: i32 = 0,
14	    host: []const u8 = "",
15	    client_name: []const u8 = "",
16	};
17	
18	/// Expand a tmux format string.
19	/// Supports: #S (session), #W (window), #I (window index), #P (pane index),
20	/// #T (title), #H (hostname), #{variable_name} long form.
21	pub fn expand(alloc: std.mem.Allocator, fmt: []const u8, ctx: *const FormatContext) ![]u8 {
22	    var result: std.ArrayListAligned(u8, null) = .empty;
23	    errdefer result.deinit(alloc);
24	
25	    var i: usize = 0;
26	    while (i < fmt.len) {
27	        if (fmt[i] != '#') {
28	            try result.append(alloc, fmt[i]);
29	            i += 1;
30	            continue;
31	        }
32	
33	        i += 1; // skip #
34	        if (i >= fmt.len) break;
35	
36	        switch (fmt[i]) {
37	            '#' => {
38	                try result.append(alloc, '#');
39	                i += 1;
40	            },
41	            'S' => {
42	                try result.appendSlice(alloc, ctx.session_name);
43	                i += 1;
44	            },
45	            'W' => {
46	                try result.appendSlice(alloc, ctx.window_name);
47	                i += 1;
48	            },
49	            'I' => {
50	                var buf: [16]u8 = undefined;
51	                const s = std.fmt.bufPrint(&buf, "{d}", .{ctx.window_index}) catch "?";
52	                try result.appendSlice(alloc, s);
53	                i += 1;
54	            },
55	            'P' => {
56	                var buf: [16]u8 = undefined;
57	                const s = std.fmt.bufPrint(&buf, "{d}", .{ctx.pane_index}) catch "?";
58	                try result.appendSlice(alloc, s);
59	                i += 1;
60	            },
61	            'T' => {
62	                try result.appendSlice(alloc, ctx.pane_title);
63	                i += 1;
64	            },
65	            'H' => {
66	                try result.appendSlice(alloc, ctx.host);
67	                i += 1;
68	            },
69	            '{' => {
70	                // Long form: #{variable_name}
