        if (i >= fmt.len) break;

        switch (fmt[i]) {
            '#' => {
                try result.append(alloc, '#');
                i += 1;
            },
            'S' => {
                try result.appendSlice(alloc, ctx.session_name);
                i += 1;
            },
            'W' => {
                try result.appendSlice(alloc, ctx.window_name);
                i += 1;
            },
            'I' => {
