/// Command execution context.
pub const Context = struct {
    server: *Server,
    session: ?*Session,
    window: ?*Window,
    pane: ?*Pane,
    client_index: ?usize = null,
    allocator: std.mem.Allocator,
    reply_fd: ?std.c.fd_t = null,
    registry: ?*const Registry = null,
    binding_manager: ?*binding_mod.BindingManager = null,
};

/// Command handler function type.
pub const Handler = *const fn (ctx: *Context, args: []const []const u8) CmdError!void;

pub const CmdError = error{
    InvalidArgs,
    SessionNotFound,
    WindowNotFound,
    PaneNotFound,
    BufferNotFound,
    CommandFailed,
    OutOfMemory,
};

/// Shared flag parser for tmux-compatible command arguments.
///
/// Flag spec format: each character is a boolean flag; append ':' for flags
/// that take a value argument.  Example: "adDEPX" + "c:e:F:f:n:s:t:x:y:"
/// means -a, -d, -D, -E, -P, -X are booleans and -c, -e, -F, -f, -n, -s,
/// -t, -x, -y each consume the next argument.
pub const FlagParser = struct {
    bool_flags: u128 = 0,
    values: [128]?[]const u8 = .{null} ** 128,
    positional: [64][]const u8 = undefined,
    positional_count: usize = 0,
    err_flag: ?u8 = null,

    /// Parse args according to the given flag spec.
    /// Returns a populated FlagParser or sets err_flag on unknown flag.
    pub fn parse(spec: []const u8, args: []const []const u8) FlagParser {
        var self = FlagParser{};

        var i: usize = 0;
        while (i < args.len) : (i += 1) {
            const arg = args[i];
            if (arg.len < 2 or arg[0] != '-') {
                // Not a flag u2014 this and all remaining are positional.
                while (i < args.len) : (i += 1) {
                    if (self.positional_count < self.positional.len) {
                        self.positional[self.positional_count] = args[i];
                        self.positional_count += 1;
                    }
                }
                break;
            }
            // Parse each character in the flag cluster (e.g., "-adD").
            for (arg[1..]) |ch| {
                if (ch > 127) continue;
                if (isValueFlag(spec, ch)) {
                    // Consume next argument as value.
                    i += 1;
                    if (i < args.len) {
                        self.values[ch] = args[i];
                    }
                    break; // value flag consumes rest of cluster
                } else if (isBoolFlag(spec, ch)) {
                    self.bool_flags |= @as(u128, 1) << @intCast(ch);
                } else {
                    self.err_flag = ch;
                }
            }
        }
        return self;
    }

    /// Check whether a boolean flag was set.
    pub fn has(self: *const FlagParser, flag: u8) bool {
        if (flag > 127) return false;
        return (self.bool_flags & (@as(u128, 1) << @intCast(flag))) != 0;
    }

    /// Get the value of a flag that takes an argument.
    pub fn get(self: *const FlagParser, flag: u8) ?[]const u8 {
        if (flag > 127) return null;
        return self.values[flag];
    }

    /// Return positional (non-flag) arguments.
    pub fn positionals(self: *const FlagParser) []const []const u8 {
        return self.positional[0..self.positional_count];
    }

    fn isBoolFlag(spec: []const u8, ch: u8) bool {
        for (spec, 0..) |s, idx| {
            if (s == ch) {
                // Not a value flag if next char isn't ':'
                if (idx + 1 < spec.len and spec[idx + 1] == ':') return false;
                return true;
            }
        }
        return false;
    }

    fn isValueFlag(spec: []const u8, ch: u8) bool {
        for (spec, 0..) |s, idx| {
            if (s == ch and idx + 1 < spec.len and spec[idx + 1] == ':') return true;
        }
        return false;
    }
};

/// A registered command.
pub const CommandDef = struct {
    name: []const u8,
    alias: ?[]const u8,
    min_args: u8,
    max_args: u8,
    usage: []const u8,
    handler: Handler,
};

/// Command registry.
pub const Registry = struct {
    commands: std.StringHashMap(CommandDef),

    pub fn init(alloc: std.mem.Allocator) Registry {
        return .{ .commands = std.StringHashMap(CommandDef).init(alloc) };
    }

    pub fn deinit(self: *Registry) void {
        self.commands.deinit();
    }

    pub fn register(self: *Registry, def: CommandDef) !void {
        try self.commands.put(def.name, def);
        if (def.alias) |alias| {
            try self.commands.put(alias, def);
        }
    }

    pub fn find(self: *const Registry, name: []const u8) ?CommandDef {
        return self.commands.get(name);
    }

    /// Return a sorted, deduplicated list of all commands (aliases excluded).
    pub fn listAll(self: *const Registry, alloc: std.mem.Allocator) ![]CommandDef {
        var seen = std.StringHashMap(void).init(alloc);
        defer seen.deinit();
        var list: std.ArrayListAligned(CommandDef, null) = .empty;
        defer list.deinit(alloc);

        var iter = self.commands.iterator();
        while (iter.next()) |entry| {
            const def = entry.value_ptr.*;
            if (seen.contains(def.name)) continue;
            try seen.put(def.name, {});
            try list.append(alloc, def);
        }

        const items = try alloc.dupe(CommandDef, list.items);
        std.mem.sort(CommandDef, items, {}, struct {
            fn lessThan(_: void, a: CommandDef, b: CommandDef) bool {
                return std.mem.order(u8, a.name, b.name) == .lt;
            }
        }.lessThan);
        return items;
    }

    /// Execute a command by name with arguments.
    pub fn execute(self: *const Registry, ctx: *Context, name: []const u8, args: []const []const u8) CmdError!void {
        const def = self.find(name) orelse return CmdError.CommandFailed;
        if (args.len < def.min_args or (def.max_args > 0 and args.len > def.max_args)) {
            return CmdError.InvalidArgs;
        }
        return def.handler(ctx, args);
    }

    pub fn executeParsed(self: *const Registry, ctx: *Context, command: *const config_parser.Command) CmdError!void {
        return self.execute(ctx, command.name, command.args.items);
    }

