}

fn cmdLastWindow(ctx: *Context, _: []const []const u8) CmdError!void {
    const session = ctx.session orelse return CmdError.SessionNotFound;
    if (!session.lastWindow()) return CmdError.WindowNotFound;
}

fn cmdKillWindow(ctx: *Context, _: []const []const u8) CmdError!void {
    const session = ctx.session orelse return CmdError.SessionNotFound;
    const window = session.active_window orelse return CmdError.WindowNotFound;
    for (window.panes.items) |pane| {
        ctx.server.untrackPane(pane.id);
    }
    const empty = session.removeWindow(window);
    if (empty) {
        ctx.session = null;
        ctx.server.removeSession(session);
    }
}

fn cmdKillPane(ctx: *Context, _: []const []const u8) CmdError!void {
    const session = ctx.session orelse return CmdError.SessionNotFound;
    const window = session.active_window orelse return CmdError.WindowNotFound;
    const pane = window.active_pane orelse return CmdError.PaneNotFound;
    ctx.server.untrackPane(pane.id);
    const window_empty = window.removePane(pane);
    if (window_empty) {
        const session_empty = session.removeWindow(window);
        if (session_empty) {
            ctx.session = null;
            ctx.server.removeSession(session);
        }
    } else if (window.layout_root) |root| {
        root.resize(window.sx, window.sy);
    }
}

fn cmdRenameSession(ctx: *Context, args: []const []const u8) CmdError!void {
    const session = ctx.session orelse return CmdError.SessionNotFound;
    if (args.len == 0) return CmdError.InvalidArgs;
    session.rename(args[args.len - 1]) catch return CmdError.OutOfMemory;
}

fn cmdRenameWindow(ctx: *Context, args: []const []const u8) CmdError!void {
    const session = ctx.session orelse return CmdError.SessionNotFound;
    const window = session.active_window orelse return CmdError.WindowNotFound;
    if (args.len == 0) return CmdError.InvalidArgs;
    window.rename(args[args.len - 1]) catch return CmdError.OutOfMemory;
}

fn cmdResizePane(ctx: *Context, args: []const []const u8) CmdError!void {
    const session = ctx.session orelse return CmdError.SessionNotFound;
    const window = session.active_window orelse return CmdError.WindowNotFound;
    const pane = window.active_pane orelse return CmdError.PaneNotFound;

    var dx: i32 = 0;
    var dy: i32 = 0;
    var amount: u32 = 1;

    var i: usize = 0;
    while (i < args.len) : (i += 1) {
        if (std.mem.eql(u8, args[i], "-Z")) {
            _ = window.toggleZoom();
            return;
        } else if (std.mem.eql(u8, args[i], "-U")) {
            dy = -1;
        } else if (std.mem.eql(u8, args[i], "-D")) {
            dy = 1;
        } else if (std.mem.eql(u8, args[i], "-L")) {
            dx = -1;
        } else if (std.mem.eql(u8, args[i], "-R")) {
            dx = 1;
        } else {
            amount = std.fmt.parseInt(u32, args[i], 10) catch 1;
        }
    }

    if (dx == 0 and dy == 0) return;

    const new_sx = if (dx < 0)
        @max(1, pane.sx -| amount)
    else if (dx > 0)
        pane.sx + amount
    else
        pane.sx;

    const new_sy = if (dy < 0)
        @max(1, pane.sy -| amount)
    else if (dy > 0)
        pane.sy + amount
    else
        pane.sy;

    pane.resize(new_sx, new_sy);
    if (window.layout_root) |root| {
        root.resize(window.sx, window.sy);
    }
}

fn cmdSwapPane(ctx: *Context, args: []const []const u8) CmdError!void {
    const session = ctx.session orelse return CmdError.SessionNotFound;
    const window = session.active_window orelse return CmdError.WindowNotFound;

    var direction: Window.SwapDirection = .next;
    for (args) |arg| {
        if (std.mem.eql(u8, arg, "-U")) {
            direction = .prev;
        } else if (std.mem.eql(u8, arg, "-D")) {
            direction = .next;
        }
    }

    window.swapActivePane(direction);
}

fn cmdDisplayMessage(ctx: *Context, args: []const []const u8) CmdError!void {
    if (args.len > 0) {
        try writeOutput(ctx, "{s}\n", .{args[args.len - 1]});
    }
}

fn cmdSetOption(ctx: *Context, args: []const []const u8) CmdError!void {
    if (args.len < 2) return CmdError.InvalidArgs;

    var is_global = false;
    var is_window = false;
    var is_server = false;
    var is_pane = false;
    var do_unset = false;
    var quiet = false;
    var index: usize = 0;
    while (index < args.len and args[index].len > 0 and args[index][0] == '-') : (index += 1) {
        for (args[index][1..]) |ch| {
            switch (ch) {
                'g' => is_global = true,
                'w' => is_window = true,
                's' => is_server = true,
                'p' => is_pane = true,
                'u' => do_unset = true,
                'q' => quiet = true,
                else => {},
            }
        }
    }

    if (index >= args.len) return CmdError.InvalidArgs;
    const name = args[index];

    // Determine scope.
    const scope: options_mod.OptionScope = if (is_server)
        .server
    else if (is_pane)
        .pane
    else if (is_window)
        .window
    else
        .session;

    // Unset: remove from the store.
    if (do_unset) {
        // For now, unset is a no-op (store doesn't support removal yet).
        _ = name;
        return;
    }

    if (index + 1 >= args.len) return CmdError.InvalidArgs;
    const value = args[index + 1];

    // Write to OptionsStore.
    const opt_value = parseOptionValue(name, value);
    if (is_global) {
        // Global: write to the scope's store and also sync cached struct fields.
        ctx.server.options.set(scope, name, opt_value) catch return CmdError.OutOfMemory;
        for (ctx.server.sessions.items) |session| {
            syncCachedSessionOption(session, name, value);
        }
    } else {
        ctx.server.options.set(scope, name, opt_value) catch return CmdError.OutOfMemory;
        // Sync cached struct fields for current session.
        if (ctx.session) |session| {
            syncCachedSessionOption(session, name, value);
        }
    }

    // Keep global_default_shell in sync for backward compat.
    if (std.mem.eql(u8, name, "default-shell") and is_global) {
        const owned = ctx.server.allocator.dupeZ(u8, value) catch return CmdError.OutOfMemory;
        if (ctx.server.global_default_shell) |old| ctx.server.allocator.free(old);
        ctx.server.global_default_shell = owned;
    }
}

/// Convert a string value into an OptionValue based on the option name.
fn parseOptionValue(name: []const u8, value: []const u8) options_mod.OptionValue {
    // Boolean options.
    if (std.mem.eql(u8, name, "mouse") or
        std.mem.eql(u8, name, "status") or
        std.mem.eql(u8, name, "visual-activity") or
        std.mem.eql(u8, name, "aggressive-resize") or
        std.mem.eql(u8, name, "remain-on-exit") or
        std.mem.eql(u8, name, "monitor-activity") or
        std.mem.eql(u8, name, "monitor-bell") or
        std.mem.eql(u8, name, "set-titles") or
        std.mem.eql(u8, name, "renumber-windows") or
        std.mem.eql(u8, name, "detach-on-destroy") or
        std.mem.eql(u8, name, "allow-passthrough") or
        std.mem.eql(u8, name, "allow-rename") or
        std.mem.eql(u8, name, "synchronize-panes"))
    {
        return .{ .boolean = parseBooleanValue(value) orelse false };
    }
    // Numeric options.
    if (std.mem.eql(u8, name, "base-index") or
        std.mem.eql(u8, name, "history-limit") or
        std.mem.eql(u8, name, "escape-time") or
        std.mem.eql(u8, name, "display-time") or
        std.mem.eql(u8, name, "buffer-limit") or
        std.mem.eql(u8, name, "message-limit") or
        std.mem.eql(u8, name, "lock-after-time") or
        std.mem.eql(u8, name, "monitor-silence"))
    {
        const num = std.fmt.parseInt(i64, value, 10) catch 0;
        return .{ .number = num };
    }
    // Everything else is a string.
    return .{ .string = value };
}

/// Sync cached Session.Options struct fields when an option is set.
/// This keeps backward compatibility with code that reads Session.Options directly.
fn syncCachedSessionOption(session: *Session, name: []const u8, value: []const u8) void {
    if (std.mem.eql(u8, name, "base-index")) {
        session.options.base_index = std.fmt.parseInt(u32, value, 10) catch return;
    } else if (std.mem.eql(u8, name, "mouse")) {
        session.options.mouse = parseBooleanValue(value) orelse return;
    } else if (std.mem.eql(u8, name, "status")) {
        session.options.status = parseBooleanValue(value) orelse return;
    } else if (std.mem.eql(u8, name, "prefix")) {
        session.options.prefix_key = parsePrefixValue(value) orelse return;
    } else if (std.mem.eql(u8, name, "default-shell")) {
        session.setDefaultShell(value) catch {};
    } else if (std.mem.eql(u8, name, "visual-activity")) {
        session.options.visual_activity = parseBooleanValue(value) orelse return;
    }
}

fn cmdSourceFile(ctx: *Context, args: []const []const u8) CmdError!void {
    if (args.len == 0) return CmdError.InvalidArgs;
    const path = args[args.len - 1];

    var path_buf: [4096]u8 = .{0} ** 4096;
    if (path.len >= path_buf.len) return CmdError.CommandFailed;
    @memcpy(path_buf[0..path.len], path);
    const cpath: [*:0]const u8 = @ptrCast(path_buf[0..path.len :0]);
    const fd = std.c.open(cpath, .{ .ACCMODE = .RDONLY }, @as(std.c.mode_t, 0));
    if (fd < 0) return CmdError.CommandFailed;
    defer _ = std.c.close(fd);

    var content_buf: [65536]u8 = undefined;
    var total: usize = 0;
    while (total < content_buf.len) {
        const n = std.c.read(fd, content_buf[total..].ptr, content_buf.len - total);
        if (n <= 0) break;
        total += @intCast(n);
    }
    if (total == 0) return;

    try executeCommandString(ctx, content_buf[0..total]);
}

