fn cmdShowOptions(ctx: *Context, args: []const []const u8) CmdError!void {
    var is_global = false;
    var is_server = false;
    var is_window = false;
    var is_pane = false;
    var value_only = false;
    var query_name: ?[]const u8 = null;

    var i: usize = 0;
    while (i < args.len) : (i += 1) {
        if (args[i].len > 0 and args[i][0] == '-') {
            for (args[i][1..]) |ch| {
                switch (ch) {
                    'g' => is_global = true,
                    's' => is_server = true,
                    'w' => is_window = true,
                    'p' => is_pane = true,
                    'v' => value_only = true,
                    else => {},
                }
            }
        } else {
            query_name = args[i];
        }
    }

    const scope: options_mod.OptionScope = if (is_server)
        .server
    else if (is_pane)
        .pane
    else if (is_window)
        .window
    else
        .session;

    // Single option query.
    if (query_name) |name| {
        if (ctx.server.options.get(scope, name)) |val| {
            try formatOptionValue(ctx, name, val, value_only);
        } else {
            // Fall back to cached struct for backward compat.
            try showCachedOption(ctx, name);
        }
        return;
    }

    // Show all options from the store for this scope.
    const store = &ctx.server.options;
    const map = switch (scope) {
        .server => &store.server,
        .session => &store.session,
        .window => &store.window,
        .pane => &store.pane,
    };
    var iter = map.iterator();
    while (iter.next()) |entry| {
        try formatOptionValue(ctx, entry.key_ptr.*, entry.value_ptr.*, value_only);
    }
}

fn formatOptionValue(ctx: *Context, name: []const u8, val: options_mod.OptionValue, value_only: bool) CmdError!void {
    switch (val) {
        .string => |s| {
            if (value_only) {
                try writeOutput(ctx, "{s}\n", .{s});
            } else {
                try writeOutput(ctx, "{s} \"{s}\"\n", .{ name, s });
            }
        },
        .number => |n| {
            if (value_only) {
                try writeOutput(ctx, "{d}\n", .{n});
            } else {
                try writeOutput(ctx, "{s} {d}\n", .{ name, n });
            }
        },
        .boolean => |b| {
            const s = if (b) "on" else "off";
            if (value_only) {
                try writeOutput(ctx, "{s}\n", .{s});
            } else {
                try writeOutput(ctx, "{s} {s}\n", .{ name, s });
            }
        },
        .colour => |c| {
            _ = c;
            try writeOutput(ctx, "{s} (colour)\n", .{name});
        },
        .style => {
            try writeOutput(ctx, "{s} (style)\n", .{name});
        },
    }
}

fn showCachedOption(ctx: *Context, name: []const u8) CmdError!void {
    const session = ctx.session orelse return CmdError.SessionNotFound;
    if (std.mem.eql(u8, name, "base-index")) {
        try writeOutput(ctx, "base-index {d}\n", .{session.options.base_index});
    } else if (std.mem.eql(u8, name, "mouse")) {
        try writeOutput(ctx, "mouse {s}\n", .{if (session.options.mouse) "on" else "off"});
    } else if (std.mem.eql(u8, name, "status")) {
        try writeOutput(ctx, "status {s}\n", .{if (session.options.status) "on" else "off"});
    } else if (std.mem.eql(u8, name, "prefix")) {
        try writeOutput(ctx, "prefix C-{c}\n", .{@as(u8, @intCast(session.options.prefix_key + 'a' - 1))});
    } else {
        return CmdError.CommandFailed;
    }
}

