    const fp = FlagParser.parse("ds:t:", &.{ "-d", "-s", "demo", "shell-command", "arg1", "arg2" });
    try std.testing.expect(fp.has('d'));
    try std.testing.expectEqualStrings("demo", fp.get('s').?);
    const pos = fp.positionals();
    try std.testing.expectEqual(@as(usize, 3), pos.len);
    try std.testing.expectEqualStrings("shell-command", pos[0]);
    try std.testing.expectEqualStrings("arg1", pos[1]);
